@import 'tailwindcss';

/* Inter (SIL OFL) is the sans face, self-hosted as the v4.1 variable font — it
   ships with the system (open license). Berkeley Mono is a licensed typeface
   bundled here for local dev / the gallery; consumers supply their own mono. */
@font-face {
	font-family: 'Inter';
	src: url('/InterVariable.woff2') format('woff2');
	font-weight: 100 900;
	font-style: normal;
	font-display: swap;
}
@font-face {
	font-family: 'Berkeley Mono Variable';
	src: url('/Berkeley Mono Variable.woff2') format('woff2-variations');
	font-weight: 400 700;
	font-style: normal;
	font-display: swap;
}

@custom-variant dark (&:where(.dark, .dark *));

:root {
	--background: oklch(1 0 0);
	--foreground: oklch(0.27 0 0);
	--panel: oklch(0.96 0 0);
	--panel-foreground: oklch(0.27 0 0);
	--card: oklch(1 0 0);
	--card-foreground: oklch(0.27 0 0);
	--popover: oklch(1 0 0);
	--popover-foreground: oklch(0.27 0 0);
	--muted: oklch(0.97 0 0);
	--muted-foreground: oklch(0.44 0 0);
	--subtle-foreground: oklch(0.56 0 0);
	--border: oklch(0.87 0 0);
	--border-strong: oklch(0.71 0 0);
	--input: oklch(0.87 0 0);
	/* Accents operate within the Tailwind palette rungs, exposed as semantic tokens. */
	--ring: var(--color-blue-500);
	--primary: var(--color-purple-700);
	--primary-foreground: oklch(0.99 0 0);
	/* primary/destructive as an accent-on-surface (button text/border/tint). Same as
	   the base in light; goes paler in dark so colored buttons soften on the dark ground. */
	--primary-accent: var(--primary);
	/* App-bar chrome: brand-hued surface for AppBar + the integrated ThemeToggle.
	   Its OWN tokens (not --primary) because the bar is a lighter/darker spread of the
	   brand than the primary rung. To rebrand, point these at your hue's rungs — this
	   is the single override point for the bar, so components never hardcode purple. */
	--bar: var(--color-purple-200);
	--bar-foreground: var(--color-purple-900);
	--bar-border: var(--color-purple-300);
	--bar-accent: var(--color-purple-300);
	--bar-accent-foreground: var(--color-purple-950);
	--secondary: oklch(0.96 0 0);
	--secondary-foreground: oklch(0.27 0 0);
	--accent: oklch(0.96 0 0);
	--accent-foreground: oklch(0.27 0 0);
	--destructive: var(--color-red-600);
	--destructive-foreground: oklch(0.99 0 0);
	--destructive-accent: var(--destructive);
	--success: var(--color-green-600);
	--warning: var(--color-amber-400);
	--warning-strong: var(--color-amber-700);
	--destructive-strong: var(--color-red-700);
	--highlight: var(--color-amber-300);
	--chart-1: oklch(0.646 0.222 41.116);
	--chart-2: oklch(0.6 0.118 184.704);
	--chart-3: oklch(0.398 0.07 227.392);
	--chart-4: oklch(0.828 0.189 84.429);
	--chart-5: oklch(0.769 0.188 70.08);
	/* Interaction step tokens — hover/press feedback on ACCENT-tinted fills.
	   Use these instead of hand-picked alphas: `hover:bg-primary-accent/(--tint-hover)
	   active:bg-primary-accent/(--tint-active)` (thin washes: outline/ghost) and
	   `--tint-solid-*` for solid tinted fills; `hover:brightness-(--lift-hover)` for
	   gradient/filled buttons. Dark mode overrides these with LARGER steps: thin
	   accent washes lose perceived colorfulness at low luminance (Hunt effect) and
	   dark pastels clip under brightness(), so numeric parity reads as a weaker
	   hover. The parity correction lives HERE, once — never per-component. Gray-
	   ladder feedback (hover:bg-muted / active:bg-border/50) needs no tokens: the
	   surface tokens already flip per theme. */
	--tint-hover: 12%;
	--tint-active: 20%;
	--tint-solid-hover: 25%;
	--tint-solid-active: 35%;
	--lift-hover: 1.05;
	--radius: 0rem;
	interpolate-size: allow-keywords;
}

.dark {
	/* Surface ladder. Containers (Panel/Pane/CollapsibleSection bodies) sit flat on
	   the canvas and are read by their hairline border; raised chrome (headers/tab
	   strips, IconButton/Menu/Pagination) and fields share one lifted tier; muted is
	   the hover/emphasis step above it: canvas -> raised(card/panel) -> muted */
	--background: oklch(0.15 0 0);
	--foreground: oklch(0.96 0 0);
	--panel: oklch(0.2 0 0);
	--panel-foreground: oklch(0.96 0 0);
	--card: oklch(0.2 0 0);
	--card-foreground: oklch(0.96 0 0);
	--popover: oklch(0.205 0 0);
	--popover-foreground: oklch(0.96 0 0);
	--muted: oklch(0.235 0 0);
	--muted-foreground: oklch(0.72 0 0);
	--subtle-foreground: oklch(0.6 0 0);
	--border: oklch(0.34 0 0);
	--border-strong: oklch(0.48 0 0);
	--input: oklch(0.34 0 0);
	--ring: var(--color-blue-400);
	--primary: var(--color-purple-500);
	--primary-foreground: oklch(0.99 0 0);
	--primary-accent: var(--color-purple-400);
	--bar: var(--color-purple-950);
	--bar-foreground: var(--color-purple-200);
	--bar-border: var(--color-purple-900);
	--bar-accent: var(--color-purple-800);
	--bar-accent-foreground: var(--color-purple-50);
	--secondary: oklch(0.25 0 0);
	--secondary-foreground: oklch(0.96 0 0);
	--accent: oklch(0.25 0 0);
	--accent-foreground: oklch(0.96 0 0);
	--destructive: var(--color-red-500);
	--destructive-foreground: oklch(0.99 0 0);
	--destructive-accent: var(--color-red-400);
	--success: var(--color-green-500);
	--warning: var(--color-amber-400);
	--warning-strong: var(--color-amber-300);
	--destructive-strong: var(--color-red-400);
	--highlight: var(--color-amber-400);
	--chart-1: oklch(0.7 0.2 41.116);
	--chart-2: oklch(0.7 0.13 184.704);
	--chart-3: oklch(0.62 0.15 227.392);
	--chart-4: oklch(0.83 0.19 84.429);
	--chart-5: oklch(0.77 0.19 70.08);
	/* ~2x interaction steps for perceptual parity (see :root docstring). */
	--tint-hover: 20%;
	--tint-active: 30%;
	--tint-solid-hover: 35%;
	--tint-solid-active: 45%;
	--lift-hover: 1.1;
}

@theme inline {
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--color-panel: var(--panel);
	--color-panel-foreground: var(--panel-foreground);
	--color-card: var(--card);
	--color-card-foreground: var(--card-foreground);
	--color-popover: var(--popover);
	--color-popover-foreground: var(--popover-foreground);
	--color-muted: var(--muted);
	--color-muted-foreground: var(--muted-foreground);
	--color-subtle-foreground: var(--subtle-foreground);
	--color-border: var(--border);
	--color-border-strong: var(--border-strong);
	--color-input: var(--input);
	--color-ring: var(--ring);
	--color-primary: var(--primary);
	--color-primary-foreground: var(--primary-foreground);
	--color-primary-accent: var(--primary-accent);
	--color-bar: var(--bar);
	--color-bar-foreground: var(--bar-foreground);
	--color-bar-border: var(--bar-border);
	--color-bar-accent: var(--bar-accent);
	--color-bar-accent-foreground: var(--bar-accent-foreground);
	--color-secondary: var(--secondary);
	--color-secondary-foreground: var(--secondary-foreground);
	--color-accent: var(--accent);
	--color-accent-foreground: var(--accent-foreground);
	--color-destructive: var(--destructive);
	--color-destructive-foreground: var(--destructive-foreground);
	--color-destructive-accent: var(--destructive-accent);
	--color-success: var(--success);
	--color-warning: var(--warning);
	--color-warning-strong: var(--warning-strong);
	--color-destructive-strong: var(--destructive-strong);
	--color-highlight: var(--highlight);
	--color-chart-1: var(--chart-1);
	--color-chart-2: var(--chart-2);
	--color-chart-3: var(--chart-3);
	--color-chart-4: var(--chart-4);
	--color-chart-5: var(--chart-5);
	--radius: var(--radius);

	--font-mono: 'Berkeley Mono Variable', ui-monospace, 'SF Mono', Menlo, monospace;
	--font-sans: 'Inter', ui-sans-serif, system-ui, sans-serif;

	--spacing: 0.25rem;

	/* Single inset for every content box — panel/collapsible/pane bodies, code
	   blocks, callouts. Starts at 1U (4px). Bump the multiplier to reflow every
	   box at once; decoupled from --spacing so box padding moves without disturbing
	   the rest of the grid. */
	--pad-box: calc(var(--spacing) * 1);

	/* THE control height. Every single-line bordered control — buttons, text/number
	   inputs, select triggers, segmented clusters, field composites — is EXACTLY
	   `h-control` (md, 22px) or `h-control-sm` (sm, 18px). Never size such a control
	   with `py-*` (padding-derived heights drift by a pixel across components) and
	   never invent a third height. Derived from --spacing so density scaling keeps
	   the invariant; the optical audit asserts it. Exempt: inline glyph controls
	   (checkbox/radio), the app bar (--bar-height domain), multi-line areas, data
	   viz (bar tracks). */
	--spacing-control: calc(var(--spacing) * 5.5); /* 22px */
	--spacing-control-sm: calc(var(--spacing) * 4.5); /* 18px */

	/* App-bar (top chrome) height. Deliberately an integer px OUTSIDE the 4px grid:
	   the bar is thin chrome, and a fixed even height centers its ~18px ThemeToggle +
	   11px brand text on whole pixels. `py-*` here rounds unevenly and drifts the
	   contents up/down — use `h-[var(--bar-height)]` (the AppBar component does). */
	--bar-height: 20px;

	--text-2xs: 0.625rem; /* 10px */
	--text-2xs--line-height: calc(1 / 0.625);
	--text-xs: 0.6875rem; /* 11px */
	--text-xs--line-height: calc(1 / 0.6875);
	--text-sm: 0.75rem; /* 12px */
	--text-sm--line-height: calc(1 / 0.75);
	--text-base: 0.78125rem; /* 12.5px */
	--text-base--line-height: calc(1.125 / 0.78125);
	--text-lg: 0.875rem;
	--text-lg--line-height: calc(1.25 / 0.875);
	--text-xl: 0.9375rem; /* 15px */
	--text-xl--line-height: calc(1.5 / 0.9375);
	--text-2xl: 1.0625rem; /* 17px */
	--text-2xl--line-height: calc(1.75 / 1.0625);
	--text-3xl: 1.25rem;
	--text-3xl--line-height: calc(1.75 / 1.25);
	--text-4xl: 1.5rem;
	--text-4xl--line-height: calc(2 / 1.5);
	--text-5xl: 1.875rem;
	--text-5xl--line-height: calc(2.25 / 1.875);
	--text-6xl: 2.25rem;
	--text-6xl--line-height: calc(2.5 / 2.25);
	--text-7xl: 3rem;
	--text-7xl--line-height: 1;
	--text-8xl: 3.75rem;
	--text-8xl--line-height: 1;
	--text-9xl: 4.5rem;
	--text-controls-numeric: 0.78125rem; /* 12.5px */
	--text-controls-numeric--line-height: calc(1 / 0.78125);
}

@media (pointer: coarse) {
	/* Coarse pointers (touch) get a bigger grid for fat-finger targets. `--spacing`
	   is already 0.25rem in rem units, so bumping the root font-size to 18px scales
	   it (and every rem-based size) up ~12% — no separate --spacing override needed. */
	html {
		font-size: 18px;
	}
}

html {
	font-size: 16px;
	overflow: clip;
	overscroll-behavior: none;
}

html,
body {
	width: 100%;
	height: 100%;
}

body {
	margin: 0;
	/* The app shell owns scrolling; the document itself never scrolls (kills rubber-band / stuck states). */
	overflow: clip;
	overscroll-behavior: none;
	@apply bg-background text-foreground font-sans text-base;
	/* Normalize every font to Inter's cap-height (0.728) at a given font-size, so
	   mono caps + digits (labels, values) line up with sans instead of rendering
	   ~7% shorter. No-op for Inter (its cap-height already is 0.728); scales
	   Berkeley Mono up ~7%. Also steadies fallback metrics before fonts load. */
	font-size-adjust: cap-height 0.728;
}

/* Layered so Tailwind's font-* utilities (in @layer utilities) can override it.
   Unlayered, this reset would beat every font-mono on a form control. */
@layer base {
	button,
	input,
	select,
	textarea {
		font: inherit;
	}

	/* RULE: no state-transition animations. The design language is professional
	   software (DAW / After Effects) — state changes are INSTANT, never faded.
	   This kills every CSS transition globally; continuous feedback (loading
	   spinners, indeterminate bars) uses `animation`/@keyframes, which is untouched.
	   Do not add `transition-*` to components. */
	*,
	::before,
	::after {
		transition-property: none !important;
	}
}

/* Semantic type roles — the only sanctioned way to set typography.
   Never pick a raw size by hand in UI; use a role.
   Distinct sizes: 10 / 11 / 12.5 / 15 / 17.
   To retune the system, edit a role here and every usage updates. */
@utility type-display {
	@apply font-sans text-2xl font-medium;
	line-height: 1.15;
	letter-spacing: -0.01em;
}
@utility type-heading {
	@apply font-sans text-xl font-medium;
	line-height: 1.2;
	letter-spacing: -0.01em;
}
@utility type-title {
	@apply font-sans text-base;
	font-weight: 550; /* between medium (500) and semibold (600); Inter is variable */
	line-height: 1.3;
}
@utility type-body {
	@apply font-sans text-base;
	font-weight: 430; /* a hair thicker than 400 for body legibility; Inter is variable */
	line-height: 1.45;
}
/* Fine print (11px). A DENSITY escape hatch — footnotes, source/paper references,
   dense annotations — where fitting more matters more than legibility. NOT for general
   "secondary" text: de-emphasize with color (text-muted-foreground) on type-body, not
   by shrinking. Size = density; color/weight = emphasis. */
@utility type-fine {
	@apply font-sans text-xs font-normal;
	line-height: 1.4;
}
@utility type-label {
	@apply font-sans text-sm font-medium;
	line-height: 1.25;
}
@utility type-tag {
	@apply font-mono text-2xs font-medium uppercase;
	line-height: 1;
	letter-spacing: 0.06em;
}
@utility type-button {
	@apply font-mono text-xs font-medium uppercase;
	line-height: 1;
	letter-spacing: 0.04em;
}
@utility type-value {
	@apply font-mono text-controls-numeric font-medium tabular-nums;
	line-height: 1;
}
@utility type-code {
	@apply font-mono text-base font-normal;
	line-height: 1.55;
}

/* Spacing policy — spacing is owned by CONTAINERS, not components.
   Components ship margin-free; a parent stacks its children with one of these.
   Instrument-dense, matching Sequence Toy's control panel: panel bodies use one
   tight 3.2px step (its `space-y-1`), and panels butt together border-to-border.
   All gaps are multiples of the 0.25rem base grid. Retune here, everywhere updates. */
@utility stack-tight {
	@apply flex flex-col gap-1; /* 4px — parts of one control (label→field) */
}
/* Deliberately WIDER than stack-tight: a label must sit closer to its own field
   (4px) than the previous control sits above it (6px), or the stack reads as one
   crammed undifferentiated column (proximity grouping). 1.5U — half-steps are
   part of the system (h-control is 5.5U). */
@utility stack-field {
	@apply flex flex-col gap-1.5; /* 6px — controls inside a panel body */
}
@utility stack-group {
	@apply flex flex-col gap-1; /* 4px — panels within a section (prefer contiguous border-b) */
}
@utility stack-section {
	@apply flex flex-col gap-4; /* 12.8px — page sections; a real break, a healthy gap above each heading */
}

/* The one content-box inset. Every text-in-a-box uses this instead of a hand-picked
   p-* value, so box padding is consistent and bumping --pad-box reflows all of them. */
@utility pad-box {
	padding: var(--pad-box);
}

/* Prose — a block of running text. Unlike a control it carries visual mass, so it
   owns its separation from neighbours, the way @tailwindcss/typography's `prose` owns
   its children's rhythm. It's an EXPLICIT marker (only genuine prose opts in), so the
   spacing is decoupled from `type-body` — which also styles control text (inputs,
   labels, menu items) that must NOT get prose air. */
@utility prose {
	@apply type-body;
}
/* Prose owns its air, zeroed at a stack's edges (Tailwind's first/last reset) so the
   block sits flush. In @layer components so it beats Preflight's `p{margin:0}` reset
   yet still yields to an explicit margin utility. The stack's own 4px gap + this 4px
   = an 8px boundary against adjacent controls; two stacked prose blocks keep flowing. */
@layer components {
	.prose:not(:first-child) {
		margin-block-start: var(--spacing);
	}
	.prose:not(:last-child) {
		margin-block-end: var(--spacing);
	}
}
